  ('heelevel3-7c4986e7-moex-00067', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-114-a9c8416b', 'sub-heelevel3-7c4986e7-05', NULL, 'essay', '請回答下列問題：（每小題 10分，共 20分）
